import anthropic

# Detect deprecated model usage by listing known active model IDs
ACTIVE_MODELS = {
    "claude-haiku-4-5-20251001",
    "claude-sonnet-4-6",
    "claude-opus-4-8",
    # Add new models as released; remove deprecated ones
}

def audit_catalog_entries(catalog: list[dict]) -> list[dict]:
    """Flag catalog entries whose model IDs are no longer in the active set."""
    issues = []
    for entry in catalog:
        if entry["model_id"] not in ACTIVE_MODELS:
            issues.append({
                "entry": entry["model_id"],
                "issue": "deprecated or unrecognized model ID",
                "action": "migrate to current model; update catalog entry",
            })
    return issues

