from fastapi import FastAPI, Request, HTTPException
import anthropic, httpx, json

app = FastAPI()

# Catalog loaded from internal IDP or config store
CATALOG = {
    "claude-sonnet-4-6": {
        "allowed_teams": ["platform", "data-science", "product"],
        "max_data_class": "internal",
        "prohibited_use_cases": ["medical-diagnosis", "legal-advice", "hr-screening"],
    },
    "claude-haiku-4-5-20251001": {
        "allowed_teams": ["all"],
        "max_data_class": "internal",
        "prohibited_use_cases": ["legal-advice"],
    },
}

@app.post("/v1/messages")
async def proxy_messages(request: Request):
    body = await request.json()
    team = request.headers.get("X-Team-Id", "unknown")
    model = body.get("model", "")

    entry = CATALOG.get(model)
    if not entry:
        raise HTTPException(status_code=403, detail=f"Model {model!r} not in approved catalog")

    allowed = entry["allowed_teams"]
    if "all" not in allowed and team not in allowed:
        raise HTTPException(status_code=403, detail=f"Team {team!r} not approved for {model!r}")

    # Forward to Anthropic — gateway holds the actual API key
    client = anthropic.Anthropic()
    response = client.messages.create(**body)
    return response.model_dump()

