import ast, sys, pathlib, json

APPROVED_MODELS = {
    "claude-haiku-4-5-20251001",
    "claude-sonnet-4-6",
    "claude-opus-4-8",
}

violations = []

for path in pathlib.Path(sys.argv[1]).rglob("*.py"):
    try:
        tree = ast.parse(path.read_text())
    except SyntaxError:
        continue
    for node in ast.walk(tree):
        if isinstance(node, ast.Constant) and isinstance(node.value, str):
            v = node.value
            if v.startswith("claude-") and v not in APPROVED_MODELS:
                violations.append(f"{path}:{node.lineno}: unapproved model id {v!r}")

if violations:
    print("CATALOG VIOLATION — unapproved model IDs found:")
    for v in violations:
        print(f"  {v}")
    sys.exit(1)
else:
    print(f"Catalog check passed — {len(APPROVED_MODELS)} approved model(s)")
